// AnimatedLogin.jsx
import React, { useEffect, useRef, useState } from 'react';
import { TweenLite, Circ } from 'gsap';
import './AnimatedLogin.css';

const AnimatedLogin = () => {
  const canvasRef = useRef(null);
  const headerRef = useRef(null);
  const [dimensions, setDimensions] = useState({ width: 0, height: 0 });
  const [points, setPoints] = useState([]);
  const [target, setTarget] = useState({ x: 0, y: 0 });
  const [animateHeader, setAnimateHeader] = useState(true);
  const requestRef = useRef();
  const ctx = useRef(null);

  useEffect(() => {
    initHeader();
    initAnimation();
    addListeners();

    return () => {
      window.removeEventListener('mousemove', mouseMove);
      window.removeEventListener('scroll', scrollCheck);
      window.removeEventListener('resize', resize);
      cancelAnimationFrame(requestRef.current);
    };
  }, []);

  const initHeader = () => {
    const width = window.innerWidth;
    const height = window.innerHeight;
    setDimensions({ width, height });
    setTarget({ x: width / 2, y: height / 2 });

    if (headerRef.current) {
      headerRef.current.style.height = height + 'px';
    }

    if (canvasRef.current) {
      canvasRef.current.width = width;
      canvasRef.current.height = height;
      ctx.current = canvasRef.current.getContext('2d');
    }

    // Create points
    const newPoints = [];
    for (let x = 0; x < width; x = x + width / 20) {
      for (let y = 0; y < height; y = y + height / 20) {
        const px = x + Math.random() * width / 20;
        const py = y + Math.random() * height / 20;
        const p = { x: px, originX: px, y: py, originY: py };
        newPoints.push(p);
      }
    }

    // For each point find the 5 closest points
    for (let i = 0; i < newPoints.length; i++) {
      const closest = [];
      const p1 = newPoints[i];
      for (let j = 0; j < newPoints.length; j++) {
        const p2 = newPoints[j];
        if (!(p1 === p2)) {
          let placed = false;
          for (let k = 0; k < 5; k++) {
            if (!placed && !closest[k]) {
              closest[k] = p2;
              placed = true;
            }
          }
          for (let k = 0; k < 5; k++) {
            if (!placed && getDistance(p1, p2) < getDistance(p1, closest[k])) {
              closest[k] = p2;
              placed = true;
            }
          }
        }
      }
      p1.closest = closest;
    }

    // Assign circles to points
    for (let i in newPoints) {
      newPoints[i].circle = new Circle(newPoints[i], 2 + Math.random() * 2, 'rgba(255,255,255,0.3)');
    }

    setPoints(newPoints);
  };

  const addListeners = () => {
    if (!('ontouchstart' in window)) {
      window.addEventListener('mousemove', mouseMove);
    }
    window.addEventListener('scroll', scrollCheck);
    window.addEventListener('resize', resize);
  };

  const mouseMove = (e) => {
    let posx = 0;
    let posy = 0;
    if (e.pageX || e.pageY) {
      posx = e.pageX;
      posy = e.pageY;
    } else if (e.clientX || e.clientY) {
      posx = e.clientX + document.body.scrollLeft + document.documentElement.scrollLeft;
      posy = e.clientY + document.body.scrollTop + document.documentElement.scrollTop;
    }
    setTarget({ x: posx, y: posy });
  };

  const scrollCheck = () => {
    setAnimateHeader(document.body.scrollTop <= dimensions.height);
  };

  const resize = () => {
    const width = window.innerWidth;
    const height = window.innerHeight;
    if (headerRef.current) {
      headerRef.current.style.height = height + 'px';
    }
    if (canvasRef.current) {
      canvasRef.current.width = width;
      canvasRef.current.height = height;
    }
    setDimensions({ width, height });
  };

  const initAnimation = () => {
    animate();
    points.forEach(point => {
      shiftPoint(point);
    });
  };

  const animate = () => {
    if (animateHeader && ctx.current) {
      ctx.current.clearRect(0, 0, dimensions.width, dimensions.height);
      points.forEach(point => {
        // detect points in range
        if (Math.abs(getDistance(target, point)) < 4000) {
          point.active = 0.3;
          point.circle.active = 0.6;
        } else if (Math.abs(getDistance(target, point)) < 20000) {
          point.active = 0.1;
          point.circle.active = 0.3;
        } else if (Math.abs(getDistance(target, point)) < 40000) {
          point.active = 0.02;
          point.circle.active = 0.1;
        } else {
          point.active = 0;
          point.circle.active = 0;
        }

        drawLines(point);
        point.circle.draw();
      });
    }
    requestRef.current = requestAnimationFrame(animate);
  };

  const shiftPoint = (p) => {
    TweenLite.to(p, 1 + 1 * Math.random(), {
      x: p.originX - 50 + Math.random() * 100,
      y: p.originY - 50 + Math.random() * 100,
      ease: Circ.easeInOut,
      onComplete: () => {
        shiftPoint(p);
      }
    });
  };

  const drawLines = (p) => {
    if (!p.active || !ctx.current) return;
    p.closest.forEach(closest => {
      ctx.current.beginPath();
      ctx.current.moveTo(p.x, p.y);
      ctx.current.lineTo(closest.x, closest.y);
      ctx.current.strokeStyle = `rgba(156,217,249,${p.active})`;
      ctx.current.stroke();
    });
  };

  class Circle {
    constructor(pos, rad, color) {
      this.pos = pos || null;
      this.radius = rad || null;
      this.color = color || null;
      this.active = 0;
    }

    draw() {
      if (!this.active || !ctx.current) return;
      ctx.current.beginPath();
      ctx.current.arc(this.pos.x, this.pos.y, this.radius, 0, 2 * Math.PI, false);
      ctx.current.fillStyle = `rgba(156,217,249,${this.active})`;
      ctx.current.fill();
    }
  }

  const getDistance = (p1, p2) => {
    return Math.pow(p1.x - p2.x, 2) + Math.pow(p1.y - p2.y, 2);
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    // Add your login logic here
  };

  return (
    <div id="large-header" className="large-header" ref={headerRef}>
      <canvas id="demo-canvas" ref={canvasRef}></canvas>
      <div className="main-title form-block">
        <div id="title">
          <h1>login.</h1>
          <p className="thin">Log in to your account.</p>
        </div>
        <form onSubmit={handleSubmit}>
          <p>
            <input
              placeholder="username"
              name="username"
              type="text"
              id="username"
              className="field"
            />
          </p>
          <p>
            <input
              placeholder="password"
              name="password"
              type="password"
              id="password"
              className="field"
            />
          </p>
          <p>
            <input value="submit" type="submit" />
          </p>
        </form>
        <small className="thin">
          Not a member yet? <a href="#">Sign in</a>
        </small>
      </div>
    </div>
  );
};

export default AnimatedLogin;
